// WASDE Abril 2026 — valores corretos
// br_2425 = 2025/26 ABR (atual) | br_2324 = 2024/25 ABR (anterior)
const DEFAULT_SAFRA = { br_2425: 132.0, br_2324: 136.0, mu_2425: 1301.07, mu_2324: 1231.38 };

// B3 futures month → code (ex: JUL/26 → CCMN26)
const VENC_CODES = {
  JAN:'F',FEV:'G',MAR:'H',ABR:'J',MAI:'K',JUN:'M',
  JUL:'N',AGO:'Q',SET:'U',OUT:'V',NOV:'X',DEZ:'Z',
};
function vencToCode(venc) {
  const [mes, ano] = (venc||'').split('/');
  const c = VENC_CODES[(mes||'').toUpperCase().slice(0,3)];
  return c && ano ? `CCM${c}${ano.slice(-2)}` : null;
}

// ── Storage (localStorage) ───────────────────────────────────────────────────
async function sg(k) {
  try { const v = localStorage.getItem(k); return v ? JSON.parse(v) : null; }
  catch { return null; }
}
async function ss(k, v) {
  try { localStorage.setItem(k, JSON.stringify(v)); } catch {}
}

// ── Compress photo ────────────────────────────────────────────────────────────
function compress(file, dim=220, q=0.82) {
  return new Promise(res => {
    const img = new Image(), url = URL.createObjectURL(file);
    img.onload = () => {
      const s = Math.min(1, dim/Math.max(img.width,img.height));
      const c = document.createElement('canvas');
      c.width=img.width*s; c.height=img.height*s;
      c.getContext('2d').drawImage(img,0,0,c.width,c.height);
      URL.revokeObjectURL(url);
      res(c.toDataURL('image/jpeg',q));
    };
    img.src=url;
  });
}


const f2 = (n,d=2) => n!=null&&!isNaN(n) ? Number(n).toLocaleString('pt-BR',{minimumFractionDigits:d,maximumFractionDigits:d}) : '—';

